module top_module(
    input [7:0] obf_a,
    input [7:0] b,
    output [7:0] sum,
    output [7:0] difference,
    output [7:0] product,
    output [7:0] quotient
    );// Calculate sum
    assign sum = obf_a + b;

    // Calculate difference
    assign difference = (obf_a > b) ? obf_a - b : b - obf_a;

    // Calculate product
    assign product = obf_a * b;

    // Calculate quotient
    assign quotient = obf_a / b;

endmodule
